const fs=require('fs');const path=require('path');function del(targetPath){if(!fs.existsSync(targetPath)){return false;}
try{if(fs.statSync(targetPath).isDirectory()){fs.readdirSync(targetPath).forEach(file=>{const curPath=path.join(targetPath,file);if(fs.statSync(curPath).isFile()){fs.unlinkSync(curPath);}});fs.rmdirSync(targetPath);}else{fs.unlinkSync(targetPath);}
return true;}catch(error){console.error(`Error while deleting ${targetPath}: ${error.message}`);}}
module.exports={del};